  return (
    <div
      style={{
        width: props.width,
        height: props.height,
        background: props.background,
        display: 'inline-block',
      }}
    />
  );
}

export default function App() {
  return (
    <div>
      <Box width={80} height={80} background="tomato" />
      <Box width={120} height={60} background="steelblue" />
    </div>
  );
}

